def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        complexity = 1
        for m in range(1, 5):
            partial_sum = 0
            for n in range(1, 10):
                factor = (np.sin(m * n) + np.cos(ratio * n)) * np.exp(-n / (capacity + 1))
                partial_sum += factor * np.log1p(item + n)
                if partial_sum < 0:
                    partial_sum = abs(partial_sum) / (m + n)
            score += partial_sum / m
            if m % 2 == 0:
                complexity *= (1 + np.sqrt(capacity) / (m + 1))
            else:
                complexity *= (1 + np.log1p(item) / (m + 1))
        if ratio < 0.3:
            score *= complexity * 1.5
        elif ratio < 0.6:
            score *= complexity * 1.2
        else:
            score *= complexity * 0.8
        penalty = 0
        for p in range(1, 6):
            penalty += p * np.sqrt(item) * (1 + np.cos(p * ratio * np.pi))
            if penalty > score:
                penalty /= 2
                break
        score -= penalty
        if capacity < item * 1.1:
            score *= 2.0
        elif capacity < item * 1.5:
            score *= 1.5
        elif capacity > item * 5:
            score /= 3.0
        elif capacity > item * 4:
            score /= 2.0
        if ratio > 0.75:
            for q in range(1, 4):
                score += (np.log1p(capacity) * q) / (np.sqrt(item) + q)
        if score < 0:
            score = abs(score) / 3
        if np.isnan(score) or np.isinf(score):
            priorities[i] = np.inf
        else:
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
